#!/usr/bin/env bash
set -euo pipefail

COCKROACH_URL='postgresql://root@crdb.example.internal:26257/defaultdb?sslmode=require'
WEBHOOK_BASE_URL='https://runner.example.internal:8443'

cockroach sql --url "$COCKROACH_URL" --execute "SET CLUSTER SETTING kv.rangefeed.enabled = true;"
START_CURSOR=$(cockroach sql --url "$COCKROACH_URL" --execute "SELECT cluster_logical_timestamp();" --format=csv | tail -n +2 | tr -d '\r')
printf 'starting_cursor=%s\n' "$START_CURSOR"

# Mapping: app-a
# Source database: demo_a
# Selected tables: public.customers, public.orders
JOB_ID_APP_A=$(cockroach sql --url "$COCKROACH_URL" --database 'demo_a' --execute "CREATE CHANGEFEED FOR TABLE public.customers, public.orders INTO 'webhook-$WEBHOOK_BASE_URL/ingest/app-a?ca_%3D' WITH cursor = '$START_CURSOR', initial_scan = 'yes', envelope = 'enriched', enriched_properties = 'source', resolved = '5s';" --format=csv | tail -n +2 | cut -d, -f1 | tr -d '\r')
printf 'mapping_id=app-a source_database=demo_a selected_tables=public.customers, public.orders starting_cursor=%s job_id=%s\n' "$START_CURSOR" "${JOB_ID_APP_A}"

# Mapping: app-b
# Source database: demo_b
# Selected tables: public.invoices
JOB_ID_APP_B=$(cockroach sql --url "$COCKROACH_URL" --database 'demo_b' --execute "CREATE CHANGEFEED FOR TABLE public.invoices INTO 'webhook-$WEBHOOK_BASE_URL/ingest/app-b?ca_%3D' WITH cursor = '$START_CURSOR', initial_scan = 'yes', envelope = 'enriched', enriched_properties = 'source', resolved = '5s';" --format=csv | tail -n +2 | cut -d, -f1 | tr -d '\r')
printf 'mapping_id=app-b source_database=demo_b selected_tables=public.invoices starting_cursor=%s job_id=%s\n' "$START_CURSOR" "${JOB_ID_APP_B}"
